import{_ as t,o as c,c as o,ag as s}from"./chunks/framework.CTpQozEL.js";const h=JSON.parse('{"title":"테스트","description":"테스트를 로컬에서 실행하는 방법 (vitest) 및 force/coverage 모드를 사용하는 경우","frontmatter":{"title":"테스트","description":"테스트를 로컬에서 실행하는 방법 (vitest) 및 force/coverage 모드를 사용하는 경우"},"headers":[],"relativePath":"reference/test.md","filePath":"reference/test.md","lastUpdated":null}'),d={name:"reference/test.md"};function p(i,e,l,a,n,r){return c(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="테스트" tabindex="-1">테스트 <a class="header-anchor" href="#테스트" aria-label="Permalink to &quot;테스트&quot;">​</a></h1><ul><li><p>전체 테스트 킷 (스위트, 라이브, Docker): <a href="/openclaw-docs-ko/help/testing">Testing</a></p></li><li><p><code>pnpm test:force</code>: 기본 컨트롤 포트를 점유하고 있는 남은 게이트웨이 프로세스를 종료한 다음, 서버 테스트가 실행 중인 인스턴스와 충돌하지 않도록 격리된 게이트웨이 포트로 전체 Vitest 스위트를 실행합니다. 이전 게이트웨이 실행으로 인해 포트 18789가 점유된 경우 사용하십시오.</p></li><li><p><code>pnpm test:coverage</code>: <code>vitest.unit.config.ts</code>를 통해 V8 커버리지로 단위 스위트를 실행합니다. 전역 임계값은 줄/브랜치/함수/구문 70%입니다. 커버리지는 통합 집약적 진입점 (CLI 와이어링, 게이트웨이/telegram 브리지, 웹채팅 정적 서버)을 제외하여 단위 테스트 가능한 로직에 초점을 맞춥니다.</p></li><li><p><code>pnpm test:coverage:changed</code>: <code>origin/main</code> 이후 변경된 파일에 대해서만 단위 커버리지를 실행합니다.</p></li><li><p><code>pnpm test:changed</code>: diff가 라우팅 가능한 소스/테스트 파일만 수정하는 경우 변경된 git 경로를 범위가 지정된 Vitest 레인으로 확장합니다. 구성/설정 변경은 구성 편집이 필요할 때 와이어링 편집이 광범위하게 다시 실행되도록 네이티브 루트 프로젝트 실행으로 여전히 폴백합니다.</p></li><li><p><code>pnpm test</code>: 범위가 지정된 Vitest 레인을 통해 명시적 파일/디렉토리 대상을 라우팅합니다. 대상 없는 실행은 이제 하나의 거대한 루트 프로젝트 프로세스 대신 11개의 순차적 샤드 구성 (<code>vitest.full-core-unit-src.config.ts</code>, <code>vitest.full-core-unit-security.config.ts</code>, <code>vitest.full-core-unit-ui.config.ts</code>, <code>vitest.full-core-unit-support.config.ts</code>, <code>vitest.full-core-support-boundary.config.ts</code>, <code>vitest.full-core-contracts.config.ts</code>, <code>vitest.full-core-bundled.config.ts</code>, <code>vitest.full-core-runtime.config.ts</code>, <code>vitest.full-agentic.config.ts</code>, <code>vitest.full-auto-reply.config.ts</code>, <code>vitest.full-extensions.config.ts</code>)을 실행합니다.</p></li><li><p>선택된 <code>plugin-sdk</code> 및 <code>commands</code> 테스트 파일은 이제 <code>test/setup.ts</code>만 유지하는 전용 경량 레인을 통해 라우팅됩니다. 런타임 집약적 사례는 기존 레인에 있습니다.</p></li><li><p>선택된 <code>plugin-sdk</code> 및 <code>commands</code> 헬퍼 소스 파일도 <code>pnpm test:changed</code>를 해당 경량 레인의 명시적 형제 테스트에 매핑하므로 소형 헬퍼 편집이 무거운 런타임 기반 스위트를 다시 실행하지 않습니다.</p></li><li><p><code>auto-reply</code>도 이제 세 개의 전용 구성 (<code>core</code>, <code>top-level</code>, <code>reply</code>)으로 분할되어 응답 하네스가 더 가벼운 상위 레벨 상태/토큰/헬퍼 테스트를 지배하지 않습니다.</p></li><li><p>기본 Vitest 구성은 이제 <code>pool: &quot;threads&quot;</code> 및 <code>isolate: false</code>로 기본 설정되며 repo 구성 전반에 걸쳐 공유 비격리 러너가 활성화됩니다.</p></li><li><p><code>pnpm test:channels</code>는 <code>vitest.channels.config.ts</code>를 실행합니다.</p></li><li><p><code>pnpm test:extensions</code>는 <code>vitest.extensions.config.ts</code>를 실행합니다.</p></li><li><p><code>pnpm test:extensions</code>: 확장/플러그인 스위트를 실행합니다.</p></li><li><p><code>pnpm test:perf:imports</code>: Vitest 임포트 기간 + 임포트 분석 보고를 활성화하면서 명시적 파일/디렉토리 대상에 대해 범위가 지정된 레인 라우팅을 계속 사용합니다.</p></li><li><p><code>pnpm test:perf:imports:changed</code>: 동일한 임포트 프로파일링, 하지만 <code>origin/main</code> 이후 변경된 파일에 대해서만.</p></li><li><p><code>pnpm test:perf:changed:bench -- --ref &amp;lt;git-ref&amp;gt;</code>는 동일한 커밋된 git diff에 대한 네이티브 루트 프로젝트 실행과 라우팅된 변경 모드 경로를 벤치마킹합니다.</p></li><li><p><code>pnpm test:perf:changed:bench -- --worktree</code>는 먼저 커밋하지 않고 현재 워크트리 변경 세트를 벤치마킹합니다.</p></li><li><p><code>pnpm test:perf:profile:main</code>: Vitest 메인 스레드의 CPU 프로파일을 씁니다 (<code>.artifacts/vitest-main-profile</code>).</p></li><li><p><code>pnpm test:perf:profile:runner</code>: 단위 러너의 CPU + 힙 프로파일을 씁니다 (<code>.artifacts/vitest-runner-profile</code>).</p></li><li><p>게이트웨이 통합: <code>OPENCLAW_TEST_INCLUDE_GATEWAY=1 pnpm test</code> 또는 <code>pnpm test:gateway</code>를 통해 옵트인.</p></li><li><p><code>pnpm test:e2e</code>: 게이트웨이 종단 간 스모크 테스트 (멀티 인스턴스 WS/HTTP/노드 페어링)를 실행합니다. <code>vitest.e2e.config.ts</code>에서 <code>threads</code> + <code>isolate: false</code> 및 적응형 워커로 기본 설정됩니다. <code>OPENCLAW_E2E_WORKERS=&amp;lt;n&amp;gt;</code>으로 조정하고 자세한 로그는 <code>OPENCLAW_E2E_VERBOSE=1</code>을 설정하십시오.</p></li><li><p><code>pnpm test:live</code>: 프로바이더 라이브 테스트 (minimax/zai)를 실행합니다. API 키와 <code>LIVE=1</code> (또는 프로바이더별 <code>*_LIVE_TEST=1</code>)이 필요합니다.</p></li><li><p><code>pnpm test:docker:openwebui</code>: 도커화된 OpenClaw + Open WebUI를 시작하고, Open WebUI를 통해 로그인하고, <code>/api/models</code>를 확인한 다음, <code>/api/chat/completions</code>를 통해 실제 프록시 채팅을 실행합니다. 사용 가능한 라이브 모델 키 (예: <code>~/.profile</code>의 OpenAI), 외부 Open WebUI 이미지 풀이 필요하며 일반 단위/e2e 스위트처럼 CI가 안정적으로 예상되지 않습니다.</p></li><li><p><code>pnpm test:docker:mcp-channels</code>: 시드된 게이트웨이 컨테이너와 <code>openclaw mcp serve</code>를 생성하는 두 번째 클라이언트 컨테이너를 시작한 다음, 라우팅된 대화 검색, 트랜스크립트 읽기, 첨부 메타데이터, 라이브 이벤트 큐 동작, 아웃바운드 전송 라우팅, 실제 stdio 브리지를 통한 Claude 스타일 채널 + 권한 알림을 검증합니다. Claude 알림 어서션은 원시 stdio MCP 프레임을 직접 읽으므로 스모크는 브리지가 실제로 내보내는 내용을 반영합니다.</p></li></ul><h2 id="로컬-pr-게이트" tabindex="-1">로컬 PR 게이트 <a class="header-anchor" href="#로컬-pr-게이트" aria-label="Permalink to &quot;로컬 PR 게이트&quot;">​</a></h2><p>로컬 PR 랜드/게이트 검사를 위해 다음을 실행합니다:</p><ul><li><code>pnpm check</code></li><li><code>pnpm build</code></li><li><code>pnpm test</code></li><li><code>pnpm check:docs</code></li></ul><p><code>pnpm test</code>가 부하가 많은 호스트에서 불안정한 경우 회귀로 취급하기 전에 한 번 다시 실행한 다음 <code>pnpm test &amp;lt;path/to/test&amp;gt;</code>로 격리하십시오. 메모리 제한 호스트의 경우 다음을 사용하십시오:</p><ul><li><code>OPENCLAW_VITEST_MAX_WORKERS=1 pnpm test</code></li><li><code>OPENCLAW_VITEST_FS_MODULE_CACHE_PATH=/tmp/openclaw-vitest-cache pnpm test:changed</code></li></ul><h2 id="모델-지연-벤치-로컬-키" tabindex="-1">모델 지연 벤치 (로컬 키) <a class="header-anchor" href="#모델-지연-벤치-로컬-키" aria-label="Permalink to &quot;모델 지연 벤치 (로컬 키)&quot;">​</a></h2><p>스크립트: <a href="https://github.com/openclaw/openclaw/blob/main/scripts/bench-model.ts" target="_blank" rel="noreferrer"><code>scripts/bench-model.ts</code></a></p><p>사용법:</p><ul><li><code>source ~/.profile &amp;&amp; pnpm tsx scripts/bench-model.ts --runs 10</code></li><li>선택적 환경 변수: <code>MINIMAX_API_KEY</code>, <code>MINIMAX_BASE_URL</code>, <code>MINIMAX_MODEL</code>, <code>ANTHROPIC_API_KEY</code></li><li>기본 프롬프트: &quot;Reply with a single word: ok. No punctuation or extra text.&quot;</li></ul><p>마지막 실행 (2025-12-31, 20회):</p><ul><li>minimax 중앙값 1279ms (최소 1114, 최대 2431)</li><li>opus 중앙값 2454ms (최소 1224, 최대 3170)</li></ul><h2 id="cli-시작-벤치" tabindex="-1">CLI 시작 벤치 <a class="header-anchor" href="#cli-시작-벤치" aria-label="Permalink to &quot;CLI 시작 벤치&quot;">​</a></h2><p>스크립트: <a href="https://github.com/openclaw/openclaw/blob/main/scripts/bench-cli-startup.ts" target="_blank" rel="noreferrer"><code>scripts/bench-cli-startup.ts</code></a></p><p>사용법:</p><ul><li><code>pnpm test:startup:bench</code></li><li><code>pnpm test:startup:bench:smoke</code></li><li><code>pnpm test:startup:bench:save</code></li><li><code>pnpm test:startup:bench:update</code></li><li><code>pnpm test:startup:bench:check</code></li><li><code>pnpm tsx scripts/bench-cli-startup.ts</code></li><li><code>pnpm tsx scripts/bench-cli-startup.ts --runs 12</code></li><li><code>pnpm tsx scripts/bench-cli-startup.ts --preset real</code></li><li><code>pnpm tsx scripts/bench-cli-startup.ts --preset real --case status --case gatewayStatus --runs 3</code></li><li><code>pnpm tsx scripts/bench-cli-startup.ts --entry openclaw.mjs --entry-secondary dist/entry.js --preset all</code></li><li><code>pnpm tsx scripts/bench-cli-startup.ts --preset all --output .artifacts/cli-startup-bench-all.json</code></li><li><code>pnpm tsx scripts/bench-cli-startup.ts --preset real --case gatewayStatusJson --output .artifacts/cli-startup-bench-smoke.json</code></li><li><code>pnpm tsx scripts/bench-cli-startup.ts --preset real --cpu-prof-dir .artifacts/cli-cpu</code></li><li><code>pnpm tsx scripts/bench-cli-startup.ts --json</code></li></ul><p>프리셋:</p><ul><li><code>startup</code>: <code>--version</code>, <code>--help</code>, <code>health</code>, <code>health --json</code>, <code>status --json</code>, <code>status</code></li><li><code>real</code>: <code>health</code>, <code>status</code>, <code>status --json</code>, <code>sessions</code>, <code>sessions --json</code>, <code>agents list --json</code>, <code>gateway status</code>, <code>gateway status --json</code>, <code>gateway health --json</code>, <code>config get gateway.port</code></li><li><code>all</code>: 두 프리셋 모두</li></ul><p>출력에는 <code>sampleCount</code>, 평균, p50, p95, 최소/최대, 종료 코드/신호 분포, 각 명령의 최대 RSS 요약이 포함됩니다. 선택적 <code>--cpu-prof-dir</code> / <code>--heap-prof-dir</code>는 타이밍과 프로파일 캡처가 동일한 하네스를 사용하도록 실행당 V8 프로파일을 씁니다.</p><p>저장된 출력 규칙:</p><ul><li><code>pnpm test:startup:bench:smoke</code>는 <code>.artifacts/cli-startup-bench-smoke.json</code>에 대상 스모크 아티팩트를 씁니다</li><li><code>pnpm test:startup:bench:save</code>는 <code>runs=5</code> 및 <code>warmup=1</code>을 사용하여 <code>.artifacts/cli-startup-bench-all.json</code>에 전체 스위트 아티팩트를 씁니다</li><li><code>pnpm test:startup:bench:update</code>는 <code>runs=5</code> 및 <code>warmup=1</code>을 사용하여 <code>test/fixtures/cli-startup-bench.json</code>에서 체크인된 기준 픽스처를 새로 고침합니다</li></ul><p>체크인된 픽스처:</p><ul><li><code>test/fixtures/cli-startup-bench.json</code></li><li><code>pnpm test:startup:bench:update</code>로 새로 고침</li><li><code>pnpm test:startup:bench:check</code>로 현재 결과를 픽스처와 비교</li></ul><h2 id="온보딩-e2e-docker" tabindex="-1">온보딩 E2E (Docker) <a class="header-anchor" href="#온보딩-e2e-docker" aria-label="Permalink to &quot;온보딩 E2E (Docker)&quot;">​</a></h2><p>Docker는 선택 사항입니다. 이것은 컨테이너화된 온보딩 스모크 테스트에만 필요합니다.</p><p>깨끗한 Linux 컨테이너에서 전체 콜드 스타트 흐름:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/e2e/onboard-docker.sh</span></span></code></pre></div><p>이 스크립트는 의사 tty를 통해 대화형 마법사를 구동하고, 구성/워크스페이스/세션 파일을 확인한 다음, 게이트웨이를 시작하고 <code>openclaw health</code>를 실행합니다.</p><h2 id="qr-임포트-스모크-docker" tabindex="-1">QR 임포트 스모크 (Docker) <a class="header-anchor" href="#qr-임포트-스모크-docker" aria-label="Permalink to &quot;QR 임포트 스모크 (Docker)&quot;">​</a></h2><p>지원되는 Docker Node 런타임 (기본 Node 24, Node 22 호환)에서 <code>qrcode-terminal</code>이 로드되는지 확인합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:docker:qr</span></span></code></pre></div>',32)])])}const m=t(d,[["render",p]]);export{h as __pageData,m as default};
